package com.ichi2.anki.preferences

import androidx.preference.PreferenceCategory
import androidx.preference.PreferenceScreen
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.cardviewer.ViewerCommand.CommandCategory
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        val commandMappingScreen = requirePreference<PreferenceScreen>(R.string.pref_controls_screen_key)
        addAllControlPreferences(commandMappingScreen)
    }

    /** Attaches all possible [ControlPreference] elements to a given [PreferenceScreen] */
    fun addAllControlPreferences(screen: PreferenceScreen) {
        // Create a map of categories to their commands
        val commandsByCategory = ViewerCommand.values().groupBy { it.category }

        // Create a category for each CommandCategory in the defined order
        for (category in CommandCategory.values()) {
            val commands = commandsByCategory[category] ?: continue

            // Create the category
            val preferenceCategory = PreferenceCategory(screen.context).apply {
                setTitle(category.resourceId)
                key = "category_${category.name}"
            }
            screen.addPreference(preferenceCategory)

            // Add all commands in this category
            for (command in commands) {
                val preference = ControlPreference(screen.context).apply {
                    setTitle(command.resourceId)
                    key = command.preferenceKey
                    setDefaultValue(command.defaultValue.toPreferenceString())
                }
                preferenceCategory.addPreference(preference)
            }
        }
    }
}
