package com.ichi2.anki.preferences

import android.content.Context
import androidx.preference.PreferenceCategory
import androidx.preference.PreferenceScreen
import androidx.test.core.app.ApplicationProvider
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.preferences.ControlPreference
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNotNull
import org.junit.Assert.assertTrue
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner

@RunWith(RobolectricTestRunner::class)
class ControlsSettingsFragmentTest {

    /**
     * Test that all [ViewerCommand] values are assigned to a category.
     * This ensures that no command is left without a category.
     */
    @Test
    fun allCommandsHaveCategory() {
        for (command in ViewerCommand.values()) {
            assertNotNull("Command ${command.name} should have a category", command.category)
        }
    }

    /**
     * Test that all [ViewerCommand] values can be added to a preference screen
     * through [ControlsSettingsFragment.addAllControlPreferences].
     * This ensures that no command is left out of the controls settings.
     */
    @Test
    fun allCommandsAreAddedToPreferences() {
        val context = ApplicationProvider.getApplicationContext<Context>()
        val fragment = ControlsSettingsFragment()

        // Create a PreferenceScreen to add categories to
        val preferenceScreen = PreferenceScreen(context, null).apply {
            key = "test_screen"
        }

        // Add all control preferences
        fragment.addAllControlPreferences(preferenceScreen)

        // Collect all commands that were added
        val addedCommands = mutableSetOf<ViewerCommand>()
        for (i in 0 until preferenceScreen.preferenceCount) {
            val category = preferenceScreen.getPreference(i) as PreferenceCategory
            for (j in 0 until category.preferenceCount) {
                val preference = category.getPreference(j) as ControlPreference
                // Find the command associated with this preference
                val command = ViewerCommand.values().find { it.preferenceKey == preference.key }
                assertNotNull("Preference with key ${preference.key} should match a command", command)
                addedCommands.add(command!!)
            }
        }

        // Verify all commands were added
        assertEquals(
            "All ViewerCommand values should be added to the preferences",
            ViewerCommand.values().toSet(),
            addedCommands
        )
    }

    /**
     * Test that commands are grouped by category.
     * Each category should have at least one command.
     */
    @Test
    fun commandsAreGroupedByCategory() {
        val context = ApplicationProvider.getApplicationContext<Context>()
        val fragment = ControlsSettingsFragment()

        val preferenceScreen = PreferenceScreen(context, null).apply {
            key = "test_screen"
        }

        fragment.addAllControlPreferences(preferenceScreen)

        // Check that each category has at least one command
        for (category in ViewerCommand.CommandCategory.values()) {
            val categoryName = context.getString(category.resourceId)
            var found = false
            for (i in 0 until preferenceScreen.preferenceCount) {
                val prefCategory = preferenceScreen.getPreference(i) as PreferenceCategory
                if (prefCategory.title == categoryName) {
                    found = true
                    assertTrue(
                        "Category $categoryName should have at least one command",
                        prefCategory.preferenceCount > 0
                    )
                    break
                }
            }
            assertTrue("Category $categoryName should exist", found)
        }
    }
}
"}

